mapper.select:
SELECT at.alarm_tracking_id AS alarmTrackingId, at.alarm_rule_id AS alarmRuleId, i.instance_name AS instanceName, d.database_name AS databaseName, ar.metric_type AS metricType, at.current_value AS currentValue, at.consecutive_count AS consecutiveCount, at.status, at.last_checked_at AS lastCheckedAt FROM alarm_tracking at LEFT JOIN alarm_rules ar ON at.alarm_rule_id = ar.alarm_rule_id LEFT JOIN monitor_instance i ON at.instance_id = i.instance_id LEFT JOIN monitor_database d ON at.database_id = d.database_id WHERE 1=1
AND at.instance_id = #{instanceId}
AND at.status = #{status}
ORDER BY at.last_checked_at DESC
